// Функция рендеринга сетки профессий (остается без изменений, работает автоматически с новой базой)
function renderProfessionsGrid(category = "all", searchWord = "") {
    const listNode = document.getElementById("professions-container");
    if (!listNode) return;

    const filtered = professionsDatabase.filter(p => {
        const matchesCat = category === "all" || p.cat === category;
        const matchesSearch = p.title.toLowerCase().includes(searchWord.toLowerCase()) ||
            p.tags.some(t => t.toLowerCase().includes(searchWord.toLowerCase()));
        return matchesCat && matchesSearch;
    });

    listNode.innerHTML = filtered.map(p => `
        <article class="prof-card">
            <div class="prof-card-meta">
                <span style="font-size: 2rem;">${p.icon}</span>
                <span class="salary">${p.salary}</span>
            </div>
            <h3>${p.title}</h3>
            <p style="font-size:0.9rem; color:var(--text-muted); margin-top:8px; line-height:1.5;">${p.description.substring(0, 95)}...</p>
            <div class="skill-pills">
                ${p.tags.map(t => `<span>${t}</span>`).join("")}
            </div>
            <button class="btn-glow-primary open-huge-view-trigger" data-id="${p.id}" style="width:100%; padding:12px; font-size:0.9rem; border-radius:12px;">Изучить Маршрут</button>
        </article>
    `).join("");
}